# build_disk.sh - 创建并挂载 MeteorOS-X 磁盘镜像（支持 ext4 / FAT32）
# Usage: ./build_disk.sh [ext4|fat]

set -euo pipefail

IMG="disk.img"
MNT="mnt"
FS_TYPE="${1:-ext4}"
SIZE_MB="${SIZE_MB:-1024}"  # 默认磁盘大小 MB
MARGIN_MB=64               # 为防止完全填满预留空间

log() { echo -e "[INFO] $*"; }
err() { echo -e "[ERROR] $*" >&2; exit 1; }

check_command() {
    command -v "$1" >/dev/null 2>&1 || err "Required command '$1' not found. Please install."
}

create_image() {
    log "Creating disk image '${IMG}' (${SIZE_MB}MB)..."
    rm -f "${IMG}"
    dd if=/dev/zero of="${IMG}" bs=1M count="${SIZE_MB}" status=progress
}

format_image() {
    case "${FS_TYPE}" in
        ext4)
            log "Formatting as ext4..."
            check_command mkfs.ext4
            mkfs.ext4 -F "${IMG}"
            ;;
        fat|fat32)
            log "Formatting as FAT32..."
            check_command mkfs.vfat
            mkfs.vfat -F 32 "${IMG}"
            ;;
        *)
            err "Unsupported filesystem: ${FS_TYPE}. Use ext4 or fat."
            ;;
    esac
}

mount_image() {
    log "Mounting image..."
    mkdir -p "${MNT}"
    sudo mount -o loop "${IMG}" "${MNT}"
}

